SELECT id, word, category, status, created_at AS createdAt, updated_at AS updatedAt
FROM sensitive_words


        AND word LIKE CONCAT('%', #{word}, '%')


        AND category = #{category}


        AND status = #{status}


ORDER BY created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM sensitive_words


        AND word LIKE CONCAT('%', #{word}, '%')


        AND category = #{category}


        AND status = #{status}
